package il.co.dcd.composermapper.render; import il.co.dcd.composermapper.index.Indexes; import il.co.dcd.composermapper.model.FormatDef; import il.co.dcd.composermapper.service.LinkResolver; import il.co.dcd.composermapper.util.FileUtil; import java.nio.file.Path; import java.io.IOException; import java.util.Set;
public class FormatMarkdownWriter { public void write(FormatDef f, Indexes x, LinkResolver links, Path vault){ Path out=vault.resolve("formats").resolve(f.getId()+".md"); StringBuilder sb=new StringBuilder(); sb.append("# ").append(f.getId()).append("\n\n---\nentity_type: format\nentity_id: ").append(f.getId()).append("\nsource_file: ").append(f.getSourceFile()).append("\nsource_hash: ").append(FileUtil.sha256(f.getSourceFile())).append("\n---\n\n## Structure\n```xml\n").append(MarkdownSupport.tagTree(f.getRootTag(),0)).append("```\n\n## Used By Operations\n"); Set<String> ops=x.formatUsedByOperations().get(f.getId()); if(ops==null||ops.isEmpty()) sb.append("- None\n"); else ops.forEach(op->sb.append(MarkdownSupport.bullet(links.operationLink(op)))); sb.append("\n## Referenced XML Tags\n"); if(f.getReferencedXmlTags().isEmpty()) sb.append("- None\n"); else f.getReferencedXmlTags().forEach(t->sb.append(MarkdownSupport.bullet(t))); sb.append("\n## Mapped Java Classes From Tags\n"); if(f.getReferencedMappedJavaClasses().isEmpty()) sb.append("- None\n"); else f.getReferencedMappedJavaClasses().forEach(cls->sb.append(MarkdownSupport.bullet(x.classToSource().containsKey(cls)?links.classLink(cls):"Unresolved: "+MarkdownSupport.code(cls)))); sb.append("\n## Inferred External Dependencies\n"); if(f.getInferredExternalDependencies().isEmpty()) sb.append("- None\n"); else f.getInferredExternalDependencies().forEach(d->sb.append(MarkdownSupport.bullet(d))); try{ FileUtil.writeString(out,sb.toString()); }catch(IOException e){ throw new RuntimeException(e);} } }
